// Validate and extract input from webhook
const items = $input.all();
const body = items[0].json.body;

// Validate required fields
if (!body.task_description) {
  throw new Error('Missing task_description');
}
if (!body.prompt_run_id) {
  throw new Error('Missing prompt_run_id');
}

// Extract data - personality_type is now optional
const personalityType = body.personality_type || null;
const taskDescription = body.task_description;
const traitPercentages = body.trait_percentages || {};
const promptRunId = body.prompt_run_id;

// Build trait information for context (only if personality type provided)
let traitInfo = '';
if (personalityType && Object.keys(traitPercentages).length > 0) {
  const traitLabels = {
    mind: 'Mind (Introversion/Extraversion)',
    energy: 'Energy (Intuitive/Observant)',
    nature: 'Nature (Thinking/Feeling)',
    tactics: 'Tactics (Judging/Prospecting)',
    identity: 'Identity (Assertive/Turbulent)'
  };

  const formattedTraits = Object.entries(traitPercentages)
    .map(([key, value]) => {
      const label = traitLabels[key] || key;
      return `  - ${label}: ${value}%`;
    })
    .join('\n');

  traitInfo = `\nTrait Percentages:\n${formattedTraits}`;
}

return {
  prompt_run_id: promptRunId,
  personality_type: personalityType,
  has_personality: personalityType !== null,
  task_description: taskDescription,
  trait_percentages: traitPercentages,
  trait_info: traitInfo
};

// Handle API error response
const item = $input.first();
const response = item.json;
const webhookData = $node["Build LLM Prompt"].json;

let errorMessage = 'API call failed';
let errorDetails = {};

// Check if this is an n8n error (when continueOnFail is true)
if (response.errorMessage) {
  // n8n error format
  errorMessage = response.errorMessage || 'Unknown error';

  // Add description if available
  if (response.errorDescription) {
    errorDetails.description = response.errorDescription;
    // Use description as main error message if more specific
    if (response.errorDescription !== errorMessage) {
      errorMessage = response.errorDescription;
    }
  }

  // Extract error details
  if (response.errorDetails) {
    // HTTP code
    if (response.errorDetails.httpCode) {
      errorDetails.http_code = response.errorDetails.httpCode;
    }

    // Raw error message (contains the actual API response)
    if (response.errorDetails.rawErrorMessage && response.errorDetails.rawErrorMessage.length > 0) {
      const rawError = response.errorDetails.rawErrorMessage[0];

      // Try to parse if it's a JSON string
      const match = rawError.match(/\{.*\}/);
      if (match) {
        try {
          const parsed = JSON.parse(match[0].replace(/\\/g, ''));
          if (parsed.error) {
            if (parsed.error.type) {
              errorDetails.error_type = parsed.error.type;
            }
            if (parsed.error.message) {
              errorDetails.api_message = parsed.error.message;
              // Use API message as main error if more specific
              if (parsed.error.message !== errorMessage) {
                errorMessage = parsed.error.message;
              }
            }
          }
        } catch (e) {
          // If parsing fails, just store the raw message
          errorDetails.raw_error = rawError;
        }
      }
    }
  }

  // Add n8n-specific details for debugging
  if (response.n8nDetails) {
    errorDetails.node_name = response.n8nDetails.nodeName;
    errorDetails.time = response.n8nDetails.time;
  }
} else if (response.statusCode && response.statusCode !== 200) {
  // HTTP error (non-200 status) without n8n error wrapper
  errorDetails.status_code = response.statusCode;

  if (response.statusMessage) {
    errorDetails.status_message = response.statusMessage;
  }

  // Try to get error from response body
  if (response.body && response.body.error) {
    errorMessage = response.body.error.message || response.body.error.type || errorMessage;
    errorDetails.error_type = response.body.error.type;
  }
}

return {
  prompt_run_id: webhookData.prompt_run_id,
  success: false,
  error: errorMessage,
  details: errorDetails
};

// Parse the JSON response from Claude
const items = $input.all();
const response = items[0].json;

let selectedFramework = '';
let personalityApproach = null;  // Can be null if no personality type provided
let reasoning = '';
let questions = [];

// Extract text from Anthropic response
if (response.body.content && response.body.content[0]?.text) {
  const responseText = response.body.content[0].text.trim();

  try {
    // Parse JSON response
    const parsed = JSON.parse(responseText);

    selectedFramework = parsed.selected_framework || '';
    personalityApproach = parsed.personality_approach || null;  // Optional field
    reasoning = parsed.reasoning || '';
    questions = parsed.questions || [];

    // Validate we have required fields
    if (!selectedFramework || !reasoning || questions.length < 3 || questions.length > 5) {
      throw new Error('Invalid response structure: missing required fields or incorrect question count (must be 3-5)');
    }

    // Get the original data to check if personality was provided
    const webhookData = $node["Build LLM Prompt"].json;
    const hasPersonality = webhookData.has_personality;

    // Validate personality_approach if personality was provided
    if (hasPersonality) {
      if (!personalityApproach) {
        throw new Error('personality_approach is required when personality_type is provided');
      }
      if (personalityApproach !== 'amplify' && personalityApproach !== 'counterbalance') {
        throw new Error(`Invalid personality_approach value: ${personalityApproach}. Must be 'amplify' or 'counterbalance'`);
      }
    } else {
      // Without personality, personality_approach should be null
      if (personalityApproach) {
        console.log('Warning: personality_approach provided but no personality_type. Ignoring personality_approach.');
        personalityApproach = null;
      }
    }

  } catch (error) {
    throw new Error(`Failed to parse LLM response: ${error.message}. Response was: ${responseText}`);
  }
} else {
  throw new Error('Invalid response format from LLM');
}

// Get the original data
const webhookData = $node["Build LLM Prompt"].json;

return {
  prompt_run_id: webhookData.prompt_run_id,
  selected_framework: selectedFramework,
  personality_approach: personalityApproach,  // Can be null
  framework_reasoning: reasoning,
  framework_questions: questions,
  model_used: response.body.model || 'claude-3-5-haiku-20241022',
  tokens_used: {
    input: response.body.usage?.input_tokens || 0,
    output: response.body.usage?.output_tokens || 0,
    total: (response.body.usage?.input_tokens || 0) + (response.body.usage?.output_tokens || 0)
  }
};
